GUIAnimManager = {}

local updateTime = 50
local anims = {}

function GUIAnimManager:init()
    --local config = FileUtil.getConfigFromXml("guiAnim/guiAnim.xml")
    --if not config then
    --    LogUtil.log("GUIAnimManager:init not config", LogUtil.LogLevel.Error)
    --    return
    --end

    --读取GUI动画配置
    GUIAnimConfig:init("guiAnim/guiAnim.xml")

    LuaTimer:cancel(self.updateTimer)
    self.updateTimer = LuaTimer:schedule(function()
            self:update()
    end, 0, updateTime)
end

function GUIAnimManager:update()
    --local size = TableUtil.getTableSize(anims)
    --if size > 0 then
    --    LogUtil.log("GUIAnimManager:update " .. size)
    --end

    for i, anim in pairs(anims) do
        if anim.isEnd then
            anims[i] = nil
            --LogUtil.log("anims[i] = nil")
        else
            anim:update(updateTime)
            --LogUtil.log("anim:update(updateTime)")
        end
    end
end

function GUIAnimManager:playGUIAnim(window, animName, callBack)
    if not window then
        return
    end

    local guiAnim = GUIAnimConfig:getGUIAnimConfig(animName)
    if not guiAnim then
        return
    end

    local anim = GUIAnim.new(window, guiAnim, callBack)
    table.insert(anims, anim)
end

function GUIAnimManager:getUpdateTime()
    return updateTime
end

return GUIAnimManager